INSERT INTO `pages` (`id`, `page_title`, `status`, `sort_order`, `page_content`, `seo_url`, `meta_title`, `meta_keywords`, `meta_description`, `canonical_url`, `schema`, `media`, `banner_image`, `created_at`, `updated_at`) VALUES
(1, 'About Us', 1, 1, '<h1>About Us</h1><p>Welcome to our coupon website! We are dedicated to helping you save money by providing the best discount codes and deals from your favorite stores.</p><p>Our team works tirelessly to find and verify the latest coupons, ensuring you get the best possible savings on your purchases.</p><h2>Our Mission</h2><p>To make shopping more affordable for everyone by providing access to the best deals and discount codes.</p>', 'about-us', 'About Us - Coupon Website', 'about us, company info, coupon website', 'Learn more about our coupon website and our mission to help you save money.', NULL, NULL, 'uploads/pages/1758396728_DSC01860-edit-1x1.webp', 'uploads/pages/1758396728_test.webp', '2025-09-10 23:44:30', '2025-09-21 02:32:08'),
(2, 'Contact Us', 1, 2, '<h1>Contact Us</h1><p>Have a question or need help? We\'re here to assist you!</p><h2>Get in Touch</h2><p>Email: support@couponwebsite.com</p><p>Phone: +1 (555) 123-4567</p><p>Address: 123 Coupon Street, Deal City, DC 12345</p><h2>Business Hours</h2><p>Monday - Friday: 9:00 AM - 6:00 PM</p><p>Saturday: 10:00 AM - 4:00 PM</p><p>Sunday: Closed</p>', 'contact-us', 'Contact Us - Get in Touch', 'contact us, get in touch, support', 'Get in touch with us for any questions or support regarding our coupon services.', NULL, NULL, NULL, 'contact-us-banner.jpg', '2025-09-10 23:44:30', '2025-09-10 23:44:30'),
(3, 'Privacy Policy', 1, 3, '<h1>Privacy Policy</h1><p>Your privacy is important to us. This privacy policy explains how we collect, use, and protect your personal information.</p><h2>Information We Collect</h2><p>We collect information you provide directly to us, such as when you create an account or subscribe to our newsletter.</p><h2>How We Use Your Information</h2><p>We use your information to provide and improve our services, communicate with you, and personalize your experience.</p><h2>Data Protection</h2><p>We implement appropriate security measures to protect your personal information against unauthorized access, alteration, disclosure, or destruction.</p>', 'privacy-policy', 'Privacy Policy - Your Privacy Matters', 'privacy policy, data protection, privacy', 'Read our privacy policy to understand how we protect and use your personal information.', NULL, NULL, NULL, 'privacy-policy-banner.jpg', '2025-09-10 23:44:30', '2025-09-10 23:44:30'),
(4, 'Terms of Service', 1, 4, '<h1>Terms of Service</h1><p>Welcome to our website! These terms of service govern your use of our coupon website.</p><h2>Acceptance of Terms</h2><p>By accessing and using this website, you accept and agree to be bound by the terms and provision of this agreement.</p><h2>Use License</h2><p>Permission is granted to temporarily download one copy of the materials on our website for personal, non-commercial transitory viewing only.</p><h2>Disclaimer</h2><p>The materials on our website are provided on an \'as is\' basis. We make no warranties, expressed or implied.</p>', 'terms-of-service', 'Terms of Service - User Agreement', 'terms of service, user agreement, terms', 'Read our terms of service to understand the rules and guidelines for using our website.', NULL, NULL, NULL, 'terms-banner.jpg', '2025-09-10 23:44:30', '2025-09-10 23:44:30'),
(5, 'How It Works', 1, 5, '<h1>How It Works</h1><p>Saving money with our coupons is simple and easy!</p><h2>Step 1: Browse Coupons</h2><p>Search through our extensive collection of verified discount codes and deals.</p><h2>Step 2: Select Your Coupon</h2><p>Choose the coupon that best fits your shopping needs.</p><h2>Step 3: Apply at Checkout</h2><p>Copy the coupon code and apply it during checkout at the retailer\'s website.</p><h2>Step 4: Save Money</h2><p>Enjoy your savings! It\'s that simple.</p>', 'how-it-works', 'How It Works - Save Money Easily', 'how it works, save money, coupon process', 'Learn how our coupon system works and how you can start saving money today.', NULL, NULL, NULL, 'how-it-works-banner.jpg', '2025-09-10 23:44:30', '2025-09-10 23:44:30'),
(6, 'FAQ', 1, 6, '<h1>Frequently Asked Questions</h1><h2>How do I use a coupon code?</h2><p>Simply copy the coupon code and paste it into the promo code field during checkout at the retailer\'s website.</p><h2>Are all coupons verified?</h2><p>Yes, we verify all our coupons before publishing them to ensure they work.</p><h2>What if a coupon doesn\'t work?</h2><p>If a coupon doesn\'t work, please let us know and we\'ll investigate and update our database.</p><h2>How often do you update coupons?</h2><p>We update our coupons daily to ensure you have access to the latest deals.</p>', 'faq', 'Frequently Asked Questions', 'FAQ, frequently asked questions, help', 'Find answers to the most frequently asked questions about our coupon services.', NULL, NULL, NULL, 'faq-banner.jpg', '2025-09-10 23:44:30', '2025-09-10 23:44:30'),
(10, 'Home', 1, 7, NULL, 'home', 'Save Big with Exclusive Coupon Codes', 'test, testing', 'Discover thousands of verified discount codes from your favorite brands. Start saving money on every purchase today!', NULL, NULL, NULL, NULL, '2025-09-27 03:09:02', '2025-09-27 03:09:02');
